import sqlite3connection = sqlite3.connect("company.db")cursor = connection.cursor()id = input("Enter employee ID:")cursor.execute(f"SELECT * FROM employees where id ={id}")employees = cursor.fetchall()print()print("\n===== Employee List =====")print()if employees:    print(f"{'ID':<5}{'Name':<20}{'Department':<15}{'Salary':<10}")    print("-" * 50)    for employee in employees:    print(f"{employee[0]:<5} {employee[1]:<20} {employee[2]:<15} {employee[3]:<10} ")